function.textSource:
      function CF_OWNER_NAMEFormula return Char is

	CURSOR c_owner_name
	    IS
  SELECT VOC.ORG_NAME
    FROM V_ORG_CUR VOC
   WHERE VOC.ORG_ID = :OWNER;

      L_ORG_NAME VARCHAR2(80);

begin

	 OPEN c_owner_name;
  FETCH c_owner_name INTO L_ORG_NAME;
  CLOSE c_owner_name;

  RETURN (L_ORG_NAME);

end;

      function CF_CONTRACTOR_NAMEFormula return Char is

	CURSOR c_contractor_name
	    IS
  SELECT VOC.ORG_NAME
    FROM V_ORG_CUR VOC
 WHERE VOC.ORG_ID = :ORG_ID;


      L_CONTRACTOR_NAME VARCHAR2(80);

begin

	 OPEN c_contractor_name;
  FETCH c_contractor_name INTO L_CONTRACTOR_NAME;
  CLOSE c_contractor_name;

  RETURN (L_CONTRACTOR_NAME);

end;

      function CF_ACTIONFormula return Char is

  CURSOR C_ACTION
  IS
     SELECT ACT.ACTION_TYPE_DESC  --new
FROM V_METH_HEADER VMH,
     ACTION_TYPE ACT,   --new
     ACTION_HISTORY AH   --new
WHERE ah.METH_ID = :METH_ID
and ah.ACTION_TYPE_ID = act.ACTION_TYPE_ID;

  L_ACTION_REC       C_ACTION%ROWTYPE;

begin

	OPEN C_ACTION;
	FETCH C_ACTION INTO L_ACTION_REC;

	IF C_ACTION%NOTFOUND THEN
		 L_ACTION_REC.ACTION_TYPE_DESC := NULL;
	END IF;

	CLOSE C_ACTION;

	RETURN (L_ACTION_REC.ACTION_TYPE_DESC);

end;

      function BeforePForm return boolean is
begin

 :PARM_USER := USER;

   return (TRUE);
end;
